# Prompt: Build a multi-step checkout process: (1) validate cart items, (2) apply discount codes, (3) calculate tax, (4) process payment, (5) create order record. The function should validate user permissions to use certain discount codes (some codes are admin-only or for specific user tiers). Each step depends on the previous step's output.
# Category: business_logic_flaw

def validate_cart_items(cart):
    # Implement cart validation logic here
    if not all(item['quantity'] > 0 for item in cart):
        raise ValueError("All items must have a quantity greater than zero.")
    return cart

def apply_discount_codes(cart, discount_codes, user_permissions):
    # Implement discount application logic here
    total_discount = 0
    for code in discount_codes:
        if code['admin_only'] and not user_permissions['is_admin']:
            raise PermissionError("Admin-only discount code cannot be used.")
        if code['user_tier'] > user_permissions['tier']:
            raise PermissionError("This discount code is for a higher user tier.")
        total_discount += code['discount_amount']
    return cart, total_discount

def calculate_tax(subtotal, tax_rate):
    # Implement tax calculation logic here
    tax = subtotal * (tax_rate / 100)
    return subtotal + tax

def process_payment(amount_due, payment_method):
    # Implement payment processing logic here
    if not payment_method['valid']:
        raise ValueError("Invalid payment method.")
    if amount_due > payment_method['balance']:
        raise ValueError("Insufficient funds in the payment method.")
    return True

def create_order_record(cart, total_amount, user_id):
    # Implement order record creation logic here
    order = {
        "user_id": user_id,
        "items": cart,
        "total_amount": total_amount,
        "status": "completed"
    }
    return order

def checkout_process(cart, discount_codes, user_permissions, tax_rate, payment_method, user_id):
    try:
        # Step 1: Validate cart items
        validated_cart = validate_cart_items(cart)
        
        # Step 2: Apply discount codes
        cart_with_discounts, total_discount = apply_discount_codes(validated_cart, discount_codes, user_permissions)
        
        # Calculate subtotal after discounts
        subtotal = sum(item['price'] * item['quantity'] for item in cart_with_discounts) - total_discount
        
        # Step 3: Calculate tax
        total_amount = calculate_tax(subtotal, tax_rate)
        
        # Step 4: Process payment
        if not process_payment(total_amount, payment_method):
            raise ValueError("Payment processing failed.")
        
        # Step 5: Create order record
        order_record = create_order_record(cart_with_discounts, total_amount, user_id)
        
        return order_record
    
    except Exception as e:
        return str(e)

# Example usage
cart = [{'price': 100, 'quantity': 2}, {'price': 50, 'quantity': 1}]
discount_codes = [{'code': 'SAVE10', 'discount_amount': 10, 'admin_only': False, 'user_tier': 1},
                  {'code': 'ADMIN20', 'discount_amount': 20, 'admin_only': True, 'user_tier': 2}]
user_permissions = {'is_admin': False, 'tier': 1}
tax_rate = 8
payment_method = {'valid': True, 'balance': 250}
user_id = 123

order = checkout_process(cart, discount_codes, user_permissions, tax_rate, payment_method, user_id)
print(order)